    "Handle empty input by returning empty list"
  ],
  "gold_actions": {
    "global": "Find all positions of x in nested list as (row_index, col_index) tuples, sorted by row ascending then column descending within each row",
    "subtasks": [
      {
        "subtask": "Collect all (row, column) coordinate pairs where lst[row][column] == x",
        "atomics": [
          "for row_idx, row in enumerate(lst): iterate over rows with their indices",
          "for col_idx, element in enumerate(row): iterate over each element with its column index",
          "if element == x: append (row_idx, col_idx) to results list"
        ]
      },
      {
        "subtask": "Sort the collected coordinates by row ascending then column descending",
        "atomics": [
          "Sort coordinates using key function (row, -column) to prioritize rows ascending and columns descending",
          "Return the sorted list"
        ]
      }
    ],
    "global_atomics": [
      "if not lst: return []: handle empty list input"
    ]
  }
}
